const SENSITIVE_KEY_RE =
  /(token|secret|password|authorization|cookie|bearer|apikey|api_key|private[_-]?key|ssh[_-]?key|ghs_|ghp_|github[_-]?token|oidc)/i;

const API_KEY_PATTERN = /brdg_[a-z0-9]+_sk_[a-z0-9_]+/gi;
const JWT_PATTERN = /eyJ[a-zA-Z0-9_-]+\.eyJ[a-zA-Z0-9_-]+\.[a-zA-Z0-9_-]+/g;
const SHA256_BEARER = /sha256:[a-f0-9]{64}/gi;

export function isSensitiveKey(key: string): boolean {
  return SENSITIVE_KEY_RE.test(key);
}

export function redactStringValue(value: string): string {
  let out = value;
  if (value.startsWith('ghs_') || value.startsWith('ghp_') || value.startsWith('github_pat_')) {
    return '[REDACTED_GITHUB_TOKEN]';
  }
  if (value.startsWith('brdg_')) return '[REDACTED_API_KEY]';
  out = out.replace(API_KEY_PATTERN, '[REDACTED_API_KEY]');
  out = out.replace(JWT_PATTERN, '[REDACTED_JWT]');
  if (out.length > 2000) return `[REDACTED_LARGE_STRING_LEN_${out.length}]`;
  return out;
}

export function redactUnknown(input: unknown, depth = 0): unknown {
  if (depth > 32) return '[REDACTED_MAX_DEPTH]';
  if (input === null || input === undefined) return input;
  if (typeof input === 'string') return redactStringValue(input);
  if (typeof input === 'number' || typeof input === 'boolean') return input;
  if (Array.isArray(input)) return input.map((x) => redactUnknown(x, depth + 1));
  if (typeof input === 'object') {
    const o = input as Record<string, unknown>;
    const out: Record<string, unknown> = {};
    for (const [k, v] of Object.entries(o)) {
      if (isSensitiveKey(k)) {
        out[k] = '[REDACTED_FIELD]';
        continue;
      }
      out[k] = redactUnknown(v, depth + 1);
    }
    return out;
  }
  return '[REDACTED_UNSUPPORTED_TYPE]';
}

export function redactSecrets(message: string, apiKey?: string): string {
  let out = String(message ?? '');
  if (apiKey && apiKey.length > 8) {
    const esc = apiKey.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    try {
      out = out.replace(new RegExp(esc, 'g'), '[REDACTED_API_KEY]');
    } catch {
      /* ignore */
    }
  }
  out = out.replace(API_KEY_PATTERN, '[REDACTED_API_KEY]');
  out = out.replace(JWT_PATTERN, '[REDACTED_JWT]');
  // Preserve digest references; redact only if they look like bearer tokens in headers
  void SHA256_BEARER;
  return out;
}

export function safeLogMessage(message: string, apiKey?: string): string {
  return redactSecrets(message, apiKey);
}
